internal static string FromPascalCase(string input)
{
    var matches = PascalCaseWordPartsRegex().Matches(input);
    if (matches.Count == 0)
    {
        return input;
    }

    // Estimate capacity: original length + spaces between words
    var sb = new System.Text.StringBuilder(input.Length + matches.Count);
    bool allUpperOrSpace = true;
    bool hasSpace = false;

    for (int i = 0; i < matches.Count; i++)
    {
        if (i > 0)
        {
            sb.Append(' ');
            hasSpace = true;
        }

        var match = matches[i];
        var value = match.Value;
        bool isAllUpper = IsAllUpper(value);

        if (isAllUpper &&
            (value.Length > 1 || (match.Index > 0 && input[match.Index - 1] == ' ') || value == "I"))
        {
            sb.Append(value);
        }
        else
        {
            allUpperOrSpace = false;
            AppendLowerInvariant(sb, value);
        }
    }

    if (allUpperOrSpace && hasSpace)
    {
        // All words were acronyms — lowercase the whole result
        for (int i = 0; i < sb.Length; i++)
        {
            sb[i] = char.ToLowerInvariant(sb[i]);
        }
    }

    if (sb.Length > 0)
    {
        sb[0] = char.ToUpperInvariant(sb[0]);
    }

    return sb.ToString();
}

private static bool IsAllUpper(string value)
{
    for (int i = 0; i < value.Length; i++)
    {
        if (!char.IsUpper(value[i]))
        {
            return false;
        }
    }
    return true;
}

private static void AppendLowerInvariant(System.Text.StringBuilder sb, string value)
{
    for (int i = 0; i < value.Length; i++)
    {
        sb.Append(char.ToLowerInvariant(value[i]));
    }
}

